import { Schema } from '../修仙状态栏/schema';
import { generateBranch, generateNonCultivatorRoots, writeBranchToData } from '../_shared/branchGen';
import { 最大层级 } from '../_shared/costTable';
import { 读取功法生成配置, type 功法生成配置 } from '../_shared/branchConfig';

type StatData = z.infer<typeof Schema>;

// ── 修士基础树由开场注入；非修士空树由本脚本创建凡俗根基，两者的进阶分支均在此生成 ──

// ── 触发生成分支并写入 ──────────────────────────────────

// 防止重复触发：记录正在处理的功法名称
const processingSet = new Set<string>();

async function triggerBranchGeneration(
  triggerName: string,
  triggerLevel: number,
  config: 功法生成配置,
): Promise<boolean> {
  // 到头判断：目标层级超过最大层级则不再生成
  if (triggerLevel + 1 > 最大层级) {
    console.info(`[功法分支] "${triggerName}"已达层级${triggerLevel}（上限${最大层级}），到头跳过`);
    return false;
  }
  if (processingSet.has(triggerName)) return false;
  processingSet.add(triggerName);

  try {
    // 获取最新变量
    const mvuData = Mvu.getMvuData({ type: 'message', message_id: -1 });
    const statData = _.get(mvuData, 'stat_data') as StatData | undefined;
    if (!statData || !statData.功法) {
      console.warn('[功法分支] 无法获取最新变量数据');
      return false;
    }

    // 再次确认：该功法是否已有后续分支（避免并发竞争）
    const 已有后续 = Object.values(statData.功法).some(功 => 功?.前置功法 === triggerName);
    if (已有后续) {
      console.info(`[功法分支] "${triggerName}"已有后续分支（再次确认），跳过`);
      return false;
    }

    const 分支称呼 = config.道途身份 === '非修士' ? '技艺' : '功法';
    toastr.info(`新的${分支称呼}正在觉醒中……`);
    const techniques = await generateBranch(statData, triggerName, triggerLevel, config);
    if (techniques && techniques.length > 0) {
      writeBranchToData(statData, techniques);
      // 写回 MVU 变量
      if (mvuData) {
        await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: -1 });
        console.info(`[功法分支] 已为"${triggerName}"生成 ${techniques.length} 个后续${分支称呼}并写入变量`);
      }
      // 在酒馆中提示
      toastr.success(`有新的${分支称呼}觉醒了！从「${triggerName}」领悟了 ${techniques.map(t => t.名称).join('、')}`);
      return true;
    }
    return false;
  } catch (err) {
    console.error(`[功法分支] 为"${triggerName}"生成分支失败:`, err);
    return false;
  } finally {
    processingSet.delete(triggerName);
  }
}

// ── 手动生成入口（供功法树界面按钮调用）──────────────────

type 手动生成模式 = '根基' | '进阶' | '无需';

/**
 * 功法树界面按钮入口：
 * - 非修士且功法树为空时，先根据灵魂本源生成已掌握的凡俗根基；
 * - 其余情况为末端「已学 + 无后续 + 层级 < 上限」的功法/技艺补一层分支。
 */
async function 手动生成(overrides: Partial<功法生成配置> = {}): Promise<{ 模式: 手动生成模式; 已触发: string[] }> {
  const mvuData = Mvu.getMvuData({ type: 'message', message_id: -1 });
  const statData = _.get(mvuData, 'stat_data') as StatData | undefined;
  if (!statData?.功法) return { 模式: '无需', 已触发: [] };

  const config = 读取功法生成配置(overrides);
  if (statData.主角.境界 === '凡人' && statData.主角.灵根 === '无' && statData.主角.宗门 === '无') {
    config.道途身份 = '非修士';
  }

  // 非修士没有预选功法时，依据灵魂本源生成一组已掌握的凡俗根基。
  if (Object.keys(statData.功法).length === 0) {
    if (config.道途身份 === '非修士') {
      toastr.info('正在从灵魂本源中梳理凡俗技艺……');
      const roots = await generateNonCultivatorRoots(statData, config);
      if (roots?.length) {
        writeBranchToData(statData, roots);
        await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: -1 });
        const names = roots.map(root => root.名称);
        toastr.success(`已形成凡俗根基：${names.join('、')}`);
        return { 模式: '根基', 已触发: names };
      }
      toastr.warning('未能生成有效的凡俗根基，请稍后重试');
      return { 模式: '无需', 已触发: [] };
    }

    toastr.info('初始功法由开场白预加载注入，请先完成捏角与开场白');
    console.info('[功法树] /功法/ 为空，等待开场白预加载注入，本脚本不代为生成基础树');
    return { 模式: '无需', 已触发: [] };
  }

  // 扫描末端「已学+无后续+层级<上限」的功法，逐个补进阶分支
  const 已触发: string[] = [];
  for (const [名, 功] of Object.entries(statData.功法)) {
    if (!功?.已学习) continue;
    if (typeof 功.层级 === 'number' && 功.层级 >= 最大层级) continue;
    const 已有后续 = Object.values(statData.功法).some(g => g?.前置功法 === 名);
    if (已有后续) continue;
    const level = typeof 功.层级 === 'number' ? 功.层级 : 1;
    const generated = await triggerBranchGeneration(名, level, config);
    if (generated) 已触发.push(名);
  }

  if (已触发.length === 0) {
    toastr.info(`${config.道途身份 === '非修士' ? '技艺树' : '功法树'}已到头，无需更新`);
    return { 模式: '无需', 已触发: [] };
  }

  const 分支称呼 = config.道途身份 === '非修士' ? '技艺' : '功法';
  console.info(`[功法树] 手动生成：为 ${已触发.length} 个${分支称呼}触发进阶分支：${已触发.join('、')}`);
  toastr.success(`已为 ${已触发.length} 个${分支称呼}触发进阶分支生成`);
  return { 模式: '进阶', 已触发 };
}

// ── 脚本入口 ──────────────────────────────────────────

$(() => {
  errorCatched(async () => {
    await waitGlobalInitialized('Mvu');

    // 共享「手动生成」接口给功法树界面与开场 iframe（跨 iframe 调用）
    initializeGlobal('GongfaBranch', { 手动生成 });

    console.info('[功法分支生成脚本] 已加载，等待功法树界面手动触发');
    toastr.success('功法更新脚本已就绪');

    // 监听页面卸载
    $(window).on('pagehide', () => {
      console.info('[功法分支生成脚本] 已卸载');
    });
  })();
});
