/**
 * 共享模块：功法分支生成核心逻辑（AI 调用、校验、写入）
 * 从 src/功法分支生成/index.ts 提取，供开场注入按钮与状态栏参悟按钮共同使用。
 * 依赖全局的 generate / generateRaw / z / _，不依赖 MVU 变量读写。
 */
import { 查流派 } from '../开场/catalog/流派';
import { 功法列表 } from '../开场/catalog/功法';
import { 层级名, 层级消耗 } from './costTable';
import { 结算已学习功法属性 } from './techniqueAttributeBonus';
// ── JSON 提取 ──────────────────────────────────────────
export function extractJSON(text) {
    try {
        return JSON.parse(text);
    }
    catch { } // eslint-disable-line no-empty
    const lastClose = Math.max(text.lastIndexOf('}'), text.lastIndexOf(']'));
    if (lastClose === -1)
        throw new Error('AI 返回的文本中找不到 JSON');
    const closeChar = text[lastClose];
    const openChar = closeChar === '}' ? '{' : '[';
    let depth = 0;
    for (let i = lastClose; i >= 0; i--) {
        if (text[i] === closeChar)
            depth++;
        else if (text[i] === openChar)
            depth--;
        if (depth === 0) {
            const candidate = text.slice(i, lastClose + 1);
            try {
                return JSON.parse(candidate);
            }
            catch { } // eslint-disable-line no-empty
            break;
        }
    }
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
        try {
            return JSON.parse(jsonMatch[0]);
        }
        catch { } // eslint-disable-line no-empty
    }
    throw new Error('无法从 AI 返回的文本中提取有效 JSON');
}
// ── 字段名映射 ────────────────────────────────────────
const 字段映射 = {
    name: '名称',
    type: '类型',
    level: '层级',
    prerequisite: '前置功法',
    effect: '效果',
    attributeBonus: '属性加成',
    attribute_bonus: '属性加成',
    learned: '已学习',
    cost: '消耗灵悟',
    desc: '描述',
    description: '描述',
};
function 映射字段名(obj) {
    if (!obj || typeof obj !== 'object')
        return obj;
    const result = {};
    for (const [key, val] of Object.entries(obj)) {
        const mappedKey = 字段映射[key] ?? key;
        result[mappedKey] = val;
    }
    return result;
}
// ── zod 校验 schema ─────────────────────────────────────
const AI功法条目Schema = z.object({
    名称: z.string().min(1),
    类型: z.preprocess(v => {
        const s = String(v).trim();
        if (s.includes('主动') || s.startsWith('act'))
            return '主动';
        if (s.includes('被动') || s.startsWith('pass'))
            return '被动';
        return '被动';
    }, z.enum(['主动', '被动'])),
    层级: z.preprocess(v => {
        const n = Number(v);
        if (Number.isNaN(n))
            return 4;
        return _.clamp(Math.round(n), 1, 12);
    }, z.number().min(1).max(12)),
    前置功法: z.string(),
    效果: z.preprocess(v => (typeof v === 'string' ? v : String(v ?? '')), z.string()),
    属性加成: z.preprocess(v => (typeof v === 'string' ? v : String(v ?? '')), z.string().prefault('')),
    已学习: z.preprocess(v => {
        if (v === true || v === 'true' || v === 1 || v === '1')
            return true;
        return false;
    }, z.boolean()),
    消耗灵悟: z.preprocess(v => {
        const n = Number(v);
        if (Number.isNaN(n) || n <= 0)
            return 10;
        return Math.max(5, Math.round(n));
    }, z.number().min(5)),
    描述: z.preprocess(v => (typeof v === 'string' ? v : String(v ?? '')), z.string().prefault('')),
});
// ── 增量生成提示词构建 ──────────────────────────────────
/**
 * 根据道途身份构建进阶 prompt：修士延续功法体系，非修士延续凡俗技艺/人生专长。
 * 消耗灵悟由 writeBranchToData 按层级基础值与本流派折半重算，故不要求 AI 给精确数值。
 */
function buildBranchPrompt(statData, triggerName, triggerLevel, existingNames, config) {
    const 主 = statData.主角;
    const 流派 = 主.修炼流派 || '未知';
    const 灵根 = 主.灵根 || '未知';
    const 本源 = 主.本源 || '未知';
    const 目标层级 = triggerLevel + 1;
    // 触发功法所在层级附近的已有功法，作为前置链与命名参照
    const 相关 = Object.entries(statData.功法)
        .filter(([, v]) => v.层级 >= triggerLevel - 1 && v.层级 <= triggerLevel + 1)
        .map(([名, 功]) => `${名}(${功.类型},${层级名[功.层级]},前置:${功.前置功法 || '无'})`);
    const 行 = [];
    if (config.道途身份 === '非修士') {
        行.push('为非修士生成凡俗技艺/人生专长的进阶分支，结果仍使用既有“功法树”数据字段承载。');
        行.push(`灵魂本源:${本源}；本源只影响性格、执念、审美与成长方向，绝不是法力来源。`);
        行.push(`已掌握技艺:${triggerName}(第${triggerLevel}阶) → 生成第${目标层级}阶进阶技艺`);
        行.push(`相邻已有技艺:${相关.join(' | ') || '无'}`);
        行.push(`已有名称(禁重名):${[...existingNames].slice(0, 60).join('、')}`);
        行.push(`要求:2-5个;层级全为${目标层级};至少1-2个前置为${triggerName};名称2-6字，像武艺、手艺、谋略、生存本领或人生专长;效果15-30字;已学习=false;类型主动|被动`);
        行.push('硬限制:不得出现灵根、法力、御物、施法、修炼境界或凭空超自然能力；高阶只能达到传奇凡人的技艺极限。');
    }
    else {
        行.push(`为修士生成功法进阶分支。流派:${流派} 灵根:${灵根} 本源(灵魂起源):${本源}`);
        行.push(`刚学成:${triggerName}(${层级名[triggerLevel]}) → 生成${层级名[目标层级]}分支`);
        行.push(`相邻已学功法:${相关.join(' | ') || '无'}`);
        行.push(`已有功法名(禁重名):${[...existingNames].slice(0, 60).join('、')}`);
        行.push('要求:2-5个;层级全为' +
            目标层级 +
            ';至少1-2个前置为' +
            triggerName +
            ';四字古韵命名;效果15-30字;已学习=false;类型主动|被动');
        行.push(`属性加成:主动功法固定为空字符串；被动功法填写1-2项六维加成，格式如“神识+2，灵力+1”，单项不超过${Math.max(1, Math.ceil(目标层级 / 3))}，总加成不超过${Math.max(2, 目标层级)}。`);
    }
    if (config.本源基调 === '涩涩') {
        行.push('本源基调:涩涩。可在命名、效果和描述中融入暧昧、魅惑、双修或感官意象，但必须服从角色本源与当前进阶链。');
    }
    return 行.join('\n');
}
/** 非修士没有初始功法时，根据灵魂本源生成一组已掌握的凡俗根基。 */
function buildNonCultivatorRootPrompt(statData, existingNames, config) {
    const 主 = statData.主角;
    const 行 = [
        '为一名非修士生成初始“凡俗技艺/人生专长”。结果会写入功法树，但它们不是修仙功法。',
        `角色:${主.名称};身份:${主.称号 || '凡人'};开局地点:${主.出身地 || '未知'};灵魂本源:${主.本源 || '未知'}`,
        '本源表示灵魂的起源，只用于决定性格底色、执念、天赋倾向和人生轨迹，不得把本源直接变成法力或超能力。',
        `已有名称(禁重名):${[...existingNames].slice(0, 60).join('、')}`,
        '要求:生成2-4个;层级全为1;前置功法为空字符串;已学习=true;消耗灵悟=0;类型主动|被动;名称2-6字;效果15-30字。',
        '属性加成:主动技艺固定为空字符串；被动专长可填写1项“力道/体魄/身法/灵力/神识/根骨+1”，没有明确六维成长则留空。',
        '内容范围:武艺、手艺、学识、谋略、交涉、生存本领、职业技能或意志品质；至少一个主动技艺与一个被动专长。',
        '硬限制:不得出现灵根、法力、御物、施法、修炼境界或任何凭空超自然能力。',
    ];
    if (config.本源基调 === '涩涩') {
        行.push('本源基调:涩涩。可以设计魅力、情欲洞察、身体控制或亲密互动相关的凡俗专长，但不得突破非修士边界。');
    }
    return 行.join('\n');
}
const JSON输出约束 = '不要输出任何 JSON 以外的内容，不要使用 <UpdateVariable> 或任何 XML 标签。输出格式必须严格为：{"techniques":[{"名称":"...","类型":"主动|被动","层级":数字,"前置功法":"...","效果":"...","属性加成":"...","已学习":false,"消耗灵悟":数字,"描述":"..."}]}';
/**
 * 正常基调使用无预设的 generateRaw；涩涩基调使用 generate，以携带当前酒馆预设及其参数。
 * 两条路径都额外加入结构化输出约束，避免预设文风破坏 JSON。
 */
async function requestTechniques(prompt, config) {
    const engineRole = config.道途身份 === '非修士'
        ? '你是一个黑暗修仙世界中的凡人技艺与人生专长设计引擎。'
        : '你是一个修仙世界功法设计引擎。';
    const systemPrompt = `${engineRole}你的唯一任务是按照用户要求生成结构化的分支 JSON 数据。${JSON输出约束}`;
    if (config.本源基调 === '涩涩') {
        console.info('[功法分支] 涩涩本源基调：使用 generate 携带当前酒馆预设');
        return generate({
            user_input: prompt,
            should_silence: true,
            max_chat_history: 0,
            injects: [
                {
                    role: 'system',
                    content: systemPrompt,
                    position: 'in_chat',
                    depth: 0,
                    should_scan: false,
                },
            ],
        });
    }
    return generateRaw({
        user_input: prompt,
        should_silence: true,
        ordered_prompts: [{ role: 'system', content: systemPrompt }, 'user_input'],
    });
}
function parseTechniquesResult(result) {
    const text = typeof result === 'string' ? result : result.content || JSON.stringify(result);
    console.info('[功法分支] AI 返回原始文本（前300字）:', text.slice(0, 300));
    const parsed = extractJSON(text);
    const obj = parsed;
    let techniques;
    if (Array.isArray(obj)) {
        techniques = obj;
    }
    else if (obj && typeof obj === 'object') {
        techniques = obj.techniques ?? obj.功法 ?? obj.data ?? obj;
        if (!Array.isArray(techniques)) {
            techniques = Object.values(obj).find(Array.isArray) ?? techniques;
        }
    }
    else {
        techniques = obj;
    }
    if (!Array.isArray(techniques)) {
        throw new Error('AI 返回的分支数据不是数组');
    }
    return techniques;
}
// ── 校验 ──────────────────────────────────────────────
function validateBranch(techniques, triggerName, targetLevel, existingNames) {
    const 合法 = [];
    for (const raw of techniques) {
        const t = 映射字段名(raw);
        if (!t.名称 || typeof t.名称 !== 'string' || !t.名称.trim())
            continue;
        if (existingNames.has(t.名称)) {
            console.info(`[功法分支] 跳过重复名称: ${t.名称}`);
            continue;
        }
        existingNames.add(t.名称);
        const parsed = AI功法条目Schema.safeParse(t);
        if (!parsed.success) {
            console.warn(`[功法分支] 跳过无法修正的条目: ${JSON.stringify(t)}`, parsed.error.issues);
            continue;
        }
        const 功 = parsed.data;
        // 强制层级为目标层级
        if (功.层级 !== targetLevel) {
            console.info(`[功法分支] 调整层级: ${功.名称} 从 ${功.层级} 调整为 ${targetLevel}`);
            功.层级 = targetLevel;
        }
        // 进阶分支一律未学习；非修士根基会在上层映射为已掌握。
        功.已学习 = false;
        合法.push(功);
    }
    // 确保至少有 1 个功法以触发功法为前置
    const 有触发前置 = 合法.some(t => t.前置功法 === triggerName);
    if (!有触发前置 && 合法.length > 0) {
        合法[0].前置功法 = triggerName;
        console.info(`[功法分支] 自动设置"${合法[0].名称}"的前置功法为"${triggerName}"`);
    }
    return 合法;
}
// ── 增量生成主函数 ─────────────────────────────────────
/**
 * 为指定功法生成下一级分支（AI 调用）。
 * @returns 合法功法列表，或 null（生成失败/无合法结果）
 */
export async function generateBranch(statData, triggerName, triggerLevel, config) {
    const 目标层级 = triggerLevel + 1;
    const existingNames = new Set([
        ...功法列表.map(g => g.名称),
        ...Object.keys(statData.功法),
        ...Object.keys(statData.初始功法 ?? {}),
    ]);
    const prompt = buildBranchPrompt(statData, triggerName, triggerLevel, existingNames, config);
    if (!prompt)
        return null;
    const 分支类型 = config.道途身份 === '非修士' ? '技艺' : '功法';
    console.info(`[功法分支] 开始为"${triggerName}"生成第${目标层级}阶${分支类型}分支`);
    try {
        const result = await requestTechniques(prompt, config);
        let techniques;
        try {
            techniques = parseTechniquesResult(result);
        }
        catch (err) {
            console.error('[功法分支] 解析 AI 返回失败:', err);
            return null;
        }
        const 合法功法 = validateBranch(techniques, triggerName, 目标层级, existingNames);
        if (合法功法.length === 0) {
            console.warn('[功法分支] AI 生成的功法全部无效');
            return null;
        }
        console.info(`[功法分支] 成功生成 ${合法功法.length} 个第${目标层级}阶${分支类型}分支`);
        return 合法功法;
    }
    catch (err) {
        console.error('[功法分支] 生成失败:', err);
        return null;
    }
}
/** 当非修士尚无功法树根节点时，依据灵魂本源生成已掌握的凡俗根基。 */
export async function generateNonCultivatorRoots(statData, config) {
    const existingNames = new Set([
        ...功法列表.map(g => g.名称),
        ...Object.keys(statData.功法),
        ...Object.keys(statData.初始功法 ?? {}),
    ]);
    const prompt = buildNonCultivatorRootPrompt(statData, existingNames, config);
    console.info('[功法分支] 非修士功法树为空：开始生成凡俗根基');
    try {
        const result = await requestTechniques(prompt, config);
        let techniques;
        try {
            techniques = parseTechniquesResult(result);
        }
        catch (err) {
            console.error('[功法分支] 解析非修士根基失败:', err);
            return null;
        }
        const 合法根基 = validateBranch(techniques, '', 1, existingNames).map(technique => ({
            ...technique,
            层级: 1,
            前置功法: '',
            已学习: true,
            消耗灵悟: 0,
        }));
        if (合法根基.length === 0) {
            console.warn('[功法分支] AI 生成的非修士根基全部无效');
            return null;
        }
        console.info(`[功法分支] 成功生成 ${合法根基.length} 个非修士凡俗根基`);
        return 合法根基;
    }
    catch (err) {
        console.error('[功法分支] 生成非修士根基失败:', err);
        return null;
    }
}
// ── 将新功法写入变量 ────────────────────────────────────
/**
 * 把 AI 生成的新功法写入 stat_data.功法 树。
 * 修士功法名包含流派关键字时灵悟消耗打五折；非修士不套用流派折扣。
 */
export function writeBranchToData(statData, techniques) {
    const 流派关键字 = 查流派(statData.主角.修炼流派)?.关键字 ?? '';
    const 非修士 = statData.主角.境界 === '凡人' && statData.主角.灵根 === '无';
    for (const t of techniques) {
        const 名称含流派 = !非修士 && 流派关键字 && t.名称.includes(流派关键字);
        const 流派折扣 = 名称含流派 ? 0.5 : 1;
        statData.功法[t.名称] = {
            类型: t.类型,
            层级: t.层级,
            前置功法: t.前置功法,
            效果: t.效果,
            属性加成: t.类型 === '被动' ? t.属性加成 : '',
            已学习: t.已学习,
            消耗灵悟: t.已学习 && t.前置功法 === '' ? 0 : Math.max(5, Math.round(层级消耗[t.层级] * 流派折扣)),
            描述: t.描述 ?? '',
        };
    }
    // 非修士根基会以“已学习”写入；普通进阶分支均未学习，因此这里统一结算也不会提前加点。
    结算已学习功法属性(statData);
}
